// <auto-generated>
// Rust port of the .NET test-scriptagent harness.
//
// With `--init` it (re)creates a set of test "Process" workflows — one per online
// Agent node x test process (a core.process whose core.script name starts with
// "test") under a parent "test workflow folder". Without `--init` it selects the
// existing test workflows. It then drives each workflow's agent by POSTing the
// workflow id to that agent's `/api/scriptagent/execute` endpoint (the
// ScriptAgentClient equivalent), which queues it for the agent's execution
// thread to run.
//
// Prereqs: a scriptagent must be running and registered (Agent/Online), and the
// schema must hold core.process / core.script rows named "test*".
// </auto-generated>
#![allow(dead_code)]
#![allow(clippy::all)]

use std::collections::HashMap;

use common::BaseObject;
use domain::server_node_core::{ServerNodeStatus, ServerNodeType};
use domain::workflow_core::{OnFailureAction, WorkflowType};
use logic::{object_exec_unchecked, LogicContext};
use persist::{DBPersist, Row};
use serde_json::{json, Value};

/// Stored-as-string minimum timestamp (matches the domain's ISO accessor format).
const MIN_DATE: &str = "1900-01-01T00:00:00";

/// The fields of a test workflow that the exec step needs.
struct WorkflowRow {
    id: i64,
    workflow_type_id: i64,
    server_node_id: i64,
}

fn main() {
    let init = std::env::args().any(|a| a == "--init");

    let setup = if init {
        test_insert_workflows()
    } else {
        select_test_workflows()
    };

    let (workflows, agents) = match setup {
        Ok(v) => v,
        Err(e) => {
            eprintln!("test-scriptagent: setup failed: {}", e);
            std::process::exit(1);
        }
    };

    test_exec_workflows(&workflows, &agents);
}

/// `--init`: delete old test workflows, then create one Process workflow per
/// online Agent x test process under a parent folder workflow.
fn test_insert_workflows() -> Result<(Vec<WorkflowRow>, HashMap<i64, String>), String> {
    println!("test-scriptagent: deleting existing test workflows...");
    DBPersist::exec_cmd("delete from core.workflow where name like 'test%'", "default")
        .map_err(e2s)?;

    let agents = online_agents()?;
    if agents.is_empty() {
        return Err("no online Agent nodes registered — start a scriptagent first".to_string());
    }
    println!("test-scriptagent: {} online agent(s)", agents.len());

    let processes = DBPersist::select(
        "select * from core.process where script_id in \
         (select id from core.script where name like 'test%' and is_active=1)",
        "default",
    )
    .map_err(e2s)?;
    if processes.is_empty() {
        return Err("no test processes found (core.process -> core.script name like 'test%')".to_string());
    }
    println!("test-scriptagent: {} test process(es)", processes.len());

    // Parent "folder" workflow that groups the generated test workflows.
    let mut parent = BaseObject::new();
    parent.set("name", json!("test workflow folder"));
    parent.set("parent_id", json!(0));
    parent.set("is_active", json!(1));
    parent.set("workflow_type_id", json!(WorkflowType::Folder as i64));
    let parent_id = insert_workflow(&parent)?;
    println!("test-scriptagent: created parent folder workflow {}", parent_id);

    let mut workflows = Vec::new();
    for agent_id in agents.keys() {
        let mut seq = 10i64;
        for process in &processes {
            let process_id = row_i64(process, "id");
            let script_id = row_i64(process, "script_id");
            let script_name = script_name(script_id)?;

            let mut wf = BaseObject::new();
            wf.set("name", json!(format!("test {} {}", script_name, seq)));
            wf.set("workflow_type_id", json!(WorkflowType::Process as i64));
            wf.set("is_active", json!(1));
            wf.set("server_node_id", json!(agent_id));
            wf.set("process_id", json!(process_id));
            wf.set("parent_id", json!(parent_id));
            wf.set("seq", json!(seq));
            wf.set("last_start_time", json!(MIN_DATE));
            wf.set("last_end_time", json!(MIN_DATE));
            wf.set("on_failure_action_id", json!(OnFailureAction::Continue as i64));

            let id = insert_workflow(&wf)?;
            println!("test-scriptagent: inserted workflow {} - test {} {}", id, script_name, seq);
            workflows.push(WorkflowRow {
                id,
                workflow_type_id: WorkflowType::Process as i64,
                server_node_id: *agent_id,
            });
            seq += 10;
        }
    }

    Ok((workflows, agents))
}

/// Default: select the existing test Process workflows and the agents they run on.
fn select_test_workflows() -> Result<(Vec<WorkflowRow>, HashMap<i64, String>), String> {
    println!("test-scriptagent: selecting test workflows...");
    let sql = format!(
        "select * from core.workflow where name like 'test%' and workflow_type_id = {} \
         and is_active=1 order by seq",
        WorkflowType::Process as i64
    );
    let rows = DBPersist::select(&sql, "default").map_err(e2s)?;
    let workflows: Vec<WorkflowRow> = rows
        .iter()
        .map(|r| WorkflowRow {
            id: row_i64(r, "id"),
            workflow_type_id: row_i64(r, "workflow_type_id"),
            server_node_id: row_i64(r, "server_node_id"),
        })
        .collect();
    println!("test-scriptagent: selected {} workflow(s)", workflows.len());

    let mut agents = HashMap::new();
    for wf in &workflows {
        if !agents.contains_key(&wf.server_node_id) {
            if let Some(url) = agent_url(wf.server_node_id)? {
                agents.insert(wf.server_node_id, url);
            }
        }
    }
    Ok((workflows, agents))
}

/// POST each Process workflow's id to its agent's /execute endpoint.
fn test_exec_workflows(workflows: &[WorkflowRow], agents: &HashMap<i64, String>) {
    for wf in workflows {
        if wf.workflow_type_id != WorkflowType::Process as i64 {
            continue;
        }
        let url = match agents.get(&wf.server_node_id) {
            Some(u) if !u.is_empty() => u,
            _ => {
                eprintln!(
                    "test-scriptagent: workflow {} has no agent url for node {}",
                    wf.id, wf.server_node_id
                );
                continue;
            }
        };
        let endpoint = format!("{}/api/scriptagent/execute", url.trim_end_matches('/'));
        println!("test-scriptagent: executing workflow {} on {}", wf.id, endpoint);
        match ureq::post(&endpoint)
            .set("Content-Type", "application/json")
            .send_string(&wf.id.to_string())
        {
            Ok(_) => println!("  ok"),
            Err(e) => eprintln!("  error: {}", e),
        }
    }
}

// ── helpers ──────────────────────────────────────────────────────────────────

fn online_agents() -> Result<HashMap<i64, String>, String> {
    let sql = format!(
        "select * from core.server_node where server_node_type_id = {} \
         and server_node_status_id = {} and is_active=1",
        ServerNodeType::Agent as i64,
        ServerNodeStatus::Online as i64
    );
    let rows = DBPersist::select(&sql, "default").map_err(e2s)?;
    let mut agents = HashMap::new();
    for r in &rows {
        agents.insert(row_i64(r, "id"), row_str(r, "url"));
    }
    Ok(agents)
}

fn agent_url(server_node_id: i64) -> Result<Option<String>, String> {
    let sql = format!("select url from core.server_node where id = {}", server_node_id);
    let rows = DBPersist::select(&sql, "default").map_err(e2s)?;
    Ok(rows.first().map(|r| row_str(r, "url")).filter(|u| !u.is_empty()))
}

fn script_name(script_id: i64) -> Result<String, String> {
    let sql = format!("select name from core.script where id = {}", script_id);
    let rows = DBPersist::select(&sql, "default").map_err(e2s)?;
    Ok(rows.first().map(|r| row_str(r, "name")).unwrap_or_default())
}

fn insert_workflow(record: &BaseObject) -> Result<i64, String> {
    let mut ctx = LogicContext::for_record(record.clone());
    object_exec_unchecked("workflow", "insert", &mut ctx).map_err(e2s)?;
    Ok(ctx.transaction.get("id").as_i64().unwrap_or(0))
}

fn row_i64(row: &Row, key: &str) -> i64 {
    row.get(key).and_then(|v| v.as_i64()).unwrap_or(0)
}

fn row_str(row: &Row, key: &str) -> String {
    match row.get(key) {
        Some(Value::String(s)) => s.clone(),
        Some(other) => other.to_string(),
        None => String::new(),
    }
}

fn e2s<E: std::fmt::Display>(e: E) -> String {
    e.to_string()
}
